109	\begin{lemma}[Epimorphism reflection from presheaves to sheaves of modules]
110	  \label{lem:sheafOfModules_epi_of_epi_presheaf}
111	  \lean{SheafOfModules.epi_of_epi_presheaf}
112	  If $f : F \to G$ is a morphism of sheaves of $\mathcal R$-modules whose underlying morphism of presheaves $f.\mathrm{val}$ is an epi, then $f$ itself is an epi. This is immediate from the faithfulness of the forgetful functor $\mathrm{SheafOfModules}\,\mathcal R \to \mathrm{PresheafOfModules}\,\mathcal R.\mathrm{val}$ combined with the general fact that faithful functors reflect epimorphisms.
113	\end{lemma}
