126	[Coherence square underlying the cotangent quotient $\beta$]
127	  \label{lem:cotangent_exact_seq_beta_hη}
128	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeqBeta_hη}
129	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$, there is a natural transformation
130	  \[
131	    \eta \colon (g \circ f)^{-1}\struct{S} \;\longrightarrow\; f_{*}(g^{-1}\struct{S})
132	  \]
133	  between sheaves of rings on $X$, satisfying the section-level coherence $\eta \circ \phi_{2}'^{\flat} = \phi_{fg}'^{\flat}$ where $\phi_{2}'^{\flat}$ and $\phi_{fg}'^{\flat}$ are the adjoint transposes of $f^{c}$ and $(g \circ f)^{c}$ respectively. This coherence is what packages the natural map $g \circ f \to g \circ f$ on rings into the descent map underlying $\beta$; exposing it as a top-level lemma makes the descent identification with Mathlib's $\mathrm{KaehlerDifferential.map}$ tractable.
134	\end{lemma}
